optimistic_update_pattern.example_implementation:
// In useMutation options:
onMutate: async (variables) => {
  await queryClient.cancelQueries({ queryKey: ['invoices', orgId] });
  const snapshot = queryClient.getQueryData(['invoices', orgId]);
  queryClient.setQueryData(['invoices', orgId], (old) =>
    old?.data.map(item => item.id === variables.id ? { ...item, ...variables.patch } : item)
  );
  return { snapshot };
},
onError: (_err, _vars, context) => {
  if (context?.snapshot) queryClient.setQueryData(['invoices', orgId], context.snapshot);
  toast.error('Update failed — changes reverted');
},
onSettled: () => {
  queryClient.invalidateQueries({ queryKey: ['invoices', orgId] });
}
